import org.apache.kafka.streams.StreamsBuilder;
import org.apache.kafka.streams.kstream.*;
import org.apache.kafka.common.serialization.Serdes;
import org.springframework.context.annotation.*;
import org.springframework.kafka.annotation.EnableKafkaStreams;

record TradeEvent(String tradeId, String symbol, int qty, double totalValue, String type) {}

@Configuration
@EnableKafkaStreams
public class TradeFilterTopology {

    @Bean
    public KStream<String, TradeEvent> tradeStream(StreamsBuilder builder) {
        KStream<String, TradeEvent> trades = builder.stream(
            "trade-executed"
            // Consumed.with(...) — Serde configured in application.properties
        );

        trades
            .filter((key, event) -> "BUY".equals(event.type()))  // BUY only
            .mapValues(event -> event.totalValue())               // extract value
            .to("buy-trade-values",
                Produced.with(Serdes.String(), Serdes.Double())); // write to topic

        return trades;
    }
}

