import org.apache.kafka.streams.*;
import org.apache.kafka.streams.kstream.*;
import org.apache.kafka.common.serialization.Serdes;
import org.apache.kafka.common.utils.Bytes;
import org.apache.kafka.streams.state.KeyValueStore;
import org.springframework.context.annotation.*;
import org.springframework.kafka.annotation.EnableKafkaStreams;

@Configuration @EnableKafkaStreams
public class SymbolVolumeTopology {
    @Bean
    public KStream<String, TradeEvent> symbolVolumeStream(StreamsBuilder builder) {
        KStream<String, TradeEvent> trades = builder.stream("trade-executed");

        trades
            .selectKey((tradeId, event) -> event.symbol())  // re-key: tradeId → symbol
            .groupByKey()                                    // group by symbol
            .aggregate(
                () -> 0.0,                                   // initializer: start at 0
                (symbol, event, runningVolume) ->            // aggregator: sum totalValue
                    runningVolume + event.totalValue(),
                Materialized.<String, Double, KeyValueStore<Bytes, byte[]>>
                    as("symbol-volume-store")
                    .withValueSerde(Serdes.Double())         // store Double values
            )
            .toStream()
            .to("symbol-volume", Produced.with(Serdes.String(), Serdes.Double()));

        return trades;
    }
}

