        KStream<String, TradeEvent> trades = builder.stream("trade-executed");

        trades
            .selectKey((k, e) -> e.symbol())
            .groupByKey()
            .windowedBy(
                TimeWindows.ofSizeWithNoGrace(Duration.ofMinutes(5))  // 5-min tumbling
