class BuyFilterTopologyTest {
    TopologyTestDriver driver;
    TestInputTopic<String, String> inputTopic;
    TestOutputTopic<String, String> outputTopic;

    @BeforeEach void setup() {
        StreamsBuilder builder = new StreamsBuilder();

        // Build the topology:
        builder.<String,String>stream("trade-executed")
            .filter((k, v) -> v.contains("BUY"))  // simplified: check value contains BUY
            .to("buy-trades");

        Properties props = new Properties();
        props.put(StreamsConfig.APPLICATION_ID_CONFIG, "test-buy-filter");
        props.put(StreamsConfig.BOOTSTRAP_SERVERS_CONFIG, "dummy:9092");
        props.put(StreamsConfig.DEFAULT_KEY_SERDE_CLASS_CONFIG, Serdes.String().getClass());
        props.put(StreamsConfig.DEFAULT_VALUE_SERDE_CLASS_CONFIG, Serdes.String().getClass());

        driver = new TopologyTestDriver(builder.build(), props);
        inputTopic  = driver.createInputTopic("trade-executed",
            new StringSerializer(),   new StringSerializer());
        outputTopic = driver.createOutputTopic("buy-trades",
            new StringDeserializer(), new StringDeserializer());
    }

    @AfterEach void teardown() { driver.close(); }

    @Test void filter_onlyBuyTradesOutputted() {
        inputTopic.pipeInput("TRD-1", "{type:BUY,symbol:TCS}");
        inputTopic.pipeInput("TRD-2", "{type:SELL,symbol:INFY}");  // filtered out
        inputTopic.pipeInput("TRD-3", "{type:BUY,symbol:RELIANCE}");

        List<KeyValue<String,String>> records = outputTopic.readKeyValuesToList();
        assertEquals(2, records.size(), "Expected 2 BUY trades");
        assertTrue(records.get(0).value.contains("TCS"));
        assertTrue(records.get(1).value.contains("RELIANCE"));
    }
}

