import org.apache.kafka.common.serialization.*;
import java.util.*;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

class TradeCountTopologyTest {
    TopologyTestDriver driver;
    TestInputTopic<String, String> input;
    TestOutputTopic<String, Long> output;

    @BeforeEach void setup() {
        StreamsBuilder builder = new StreamsBuilder();
        builder.<String,String>stream("trade-executed")
            .selectKey((k, v) -> extractSymbol(v))  // key = symbol
            .groupByKey()
            .count(Materialized.as("count-store"))
            .toStream()
            .to("symbol-counts", Produced.with(Serdes.String(), Serdes.Long()));

        Properties props = new Properties();
        props.put(StreamsConfig.APPLICATION_ID_CONFIG, "count-test");
        props.put(StreamsConfig.BOOTSTRAP_SERVERS_CONFIG, "dummy:9092");
        props.put(StreamsConfig.DEFAULT_KEY_SERDE_CLASS_CONFIG, Serdes.String().getClass());
        props.put(StreamsConfig.DEFAULT_VALUE_SERDE_CLASS_CONFIG, Serdes.String().getClass());

        driver = new TopologyTestDriver(builder.build(), props);
        input  = driver.createInputTopic("trade-executed", new StringSerializer(), new StringSerializer());
        output = driver.createOutputTopic("symbol-counts", new StringDeserializer(), new LongDeserializer());
    }
    @AfterEach void teardown() { driver.close(); }

    // Helper:
    private String extractSymbol(String json) {
        return json.contains("TCS") ? "TCS" : json.contains("INFY") ? "INFY" : "RELIANCE";
    }

    @Test void count_accumulatesPerSymbol() {
        input.pipeInput("T1", "{symbol:TCS}");
        input.pipeInput("T2", "{symbol:TCS}");
        input.pipeInput("T3", "{symbol:TCS}");
        input.pipeInput("T4", "{symbol:INFY}");
        input.pipeInput("T5", "{symbol:INFY}");
        input.pipeInput("T6", "{symbol:RELIANCE}");

        // KTable emits on every update — read all and get latest per key:
        Map<String, Long> counts = output.readKeyValuesToMap();
        assertEquals(3L, counts.get("TCS"));
        assertEquals(2L, counts.get("INFY"));
        assertEquals(1L, counts.get("RELIANCE"));
    }
}

