import org.apache.kafka.streams.*;
import org.apache.kafka.streams.kstream.*;
import org.apache.kafka.common.serialization.Serdes;
import java.time.Duration;
import org.springframework.context.annotation.*;
import org.springframework.kafka.annotation.EnableKafkaStreams;

@Configuration @EnableKafkaStreams
public class FraudDetectionTopology {
    @Bean
    public KStream<String, PaymentEvent> fraudDetection(StreamsBuilder builder) {
        KStream<String, PaymentEvent> payments = builder.stream("payment-events");

        payments
            .groupByKey()                          // group by cardId (already the key)
            .windowedBy(TimeWindows.ofSizeWithNoGrace(Duration.ofMinutes(10)))
            .count()                               // count per card per 10-min window
            .toStream()
            .filter((windowed, count) -> count > 5)  // suspicious: > 5 in 10 minutes
            .map((windowed, count) -> KeyValue.pair(
                windowed.key(),                    // cardId
                new FraudAlert(windowed.key(), count)))  // alert payload
            .to("fraud-alerts");                   // alert consumer handles it

        return payments;
    }
}

