import org.apache.kafka.streams.*;
import org.apache.kafka.streams.kstream.*;
import org.apache.kafka.common.serialization.Serdes;
import org.apache.kafka.common.utils.Bytes;
import org.apache.kafka.streams.state.WindowStore;
import java.time.Duration;
import org.springframework.context.annotation.*;
import org.springframework.kafka.annotation.EnableKafkaStreams;

@Configuration @EnableKafkaStreams
public class RollingVolumeTopology {
    @Bean
    public KStream<String, TradeEvent> rollingVolume(StreamsBuilder builder) {
        KStream<String, TradeEvent> trades = builder.stream("trade-executed");

        trades
            .selectKey((k, e) -> e.symbol())
            .groupByKey()
            .windowedBy(
                TimeWindows.ofSizeWithNoGrace(
                    Duration.ofMinutes(5))           // window size: 5 minutes
                    .advanceBy(Duration.ofMinutes(1)) // advance every 1 minute
            )  // = hopping window
            .aggregate(
                () -> 0.0,
                (sym, event, vol) -> vol + event.totalValue(),
                Materialized.<String, Double, WindowStore<Bytes, byte[]>>
                    as("rolling-vol-store").withValueSerde(Serdes.Double())
            )
            .toStream()
            .map((windowed, vol) -> KeyValue.pair(windowed.key(), vol))
            .to("symbol-rolling-volume",
                Produced.with(Serdes.String(), Serdes.Double()));

        return trades;
    }
}

import org.apache.kafka.streams.*;
import org.apache.kafka.streams.kstream.*;
import org.springframework.context.annotation.*;
import org.springframework.kafka.annotation.EnableKafkaStreams;
import java.util.Map;

@Configuration @EnableKafkaStreams
public class TradeRoutingTopology {
    @Bean
    public KStream<String, TradeEvent> tradeRouter(StreamsBuilder builder) {
        KStream<String, TradeEvent> trades = builder.stream("trade-executed");

        // Branch by trade value:
        Map<String, KStream<String, TradeEvent>> branches = trades
            .split(Named.as("trade-size-"))
            .branch(
                (key, e) -> e.totalValue() < 10_000,          // small
                Named.as("small")
            )
            .branch(
                (key, e) -> e.totalValue() >= 10_000
                         && e.totalValue() <= 100_000,         // medium
                Named.as("medium")
            )
            .defaultBranch(Named.as("large"));                 // large (> ₹1L)

        branches.get("trade-size-small") .to("small-trades");
        branches.get("trade-size-medium").to("medium-trades");
        branches.get("trade-size-large") .to("large-trades");

        return trades;
    }
}

