import org.apache.kafka.streams.*;
import org.apache.kafka.streams.kstream.*;
import org.apache.kafka.common.serialization.*;
import java.time.*; import java.util.*;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

class WindowedCountTest {
    TopologyTestDriver driver;
    TestInputTopic<String,String> input;
    TestOutputTopic<String,Long> output;

    @BeforeEach void setup() {
        StreamsBuilder builder = new StreamsBuilder();
        builder.<String,String>stream("trades")
            .selectKey((k, v) -> v.split("::")[0])  // symbol is before ::
            .groupByKey()
            .windowedBy(TimeWindows.ofSizeWithNoGrace(Duration.ofMinutes(5)))
            .count()
            .toStream()
            .map((w, c) -> KeyValue.pair(w.key(), c))
            .to("counts", Produced.with(Serdes.String(), Serdes.Long()));

        Properties props = new Properties();
        props.put(StreamsConfig.APPLICATION_ID_CONFIG, "win-test");
        props.put(StreamsConfig.BOOTSTRAP_SERVERS_CONFIG, "dummy:9092");
        props.put(StreamsConfig.DEFAULT_KEY_SERDE_CLASS_CONFIG, Serdes.String().getClass());
        props.put(StreamsConfig.DEFAULT_VALUE_SERDE_CLASS_CONFIG, Serdes.String().getClass());

        driver = new TopologyTestDriver(builder.build(), props);
        input  = driver.createInputTopic("trades",  new StringSerializer(),   new StringSerializer());
        output = driver.createOutputTopic("counts", new StringDeserializer(), new LongDeserializer());
    }
    @AfterEach void teardown() { driver.close(); }

    @Test void windowedCount_separatesWindows() {
        Instant start = Instant.parse("2024-03-15T09:00:00Z");
        // Window 1 [9:00-9:05): 3 TCS trades
        input.pipeInput("T1", "TCS::BUY",  start);
        input.pipeInput("T2", "TCS::BUY",  start.plusSeconds(60));
        input.pipeInput("T3", "TCS::SELL", start.plusSeconds(120));
        // Window 2 [9:05-9:10): 1 TCS trade
        input.pipeInput("T4", "TCS::BUY",  start.plusSeconds(360));

        List<KeyValue<String,Long>> records = output.readKeyValuesToList();
        // Last count per window: window1 final = 3, window2 final = 1
        // Records: TCS=1, TCS=2, TCS=3 (from window1), TCS=1 (from window2)
        long lastWindow1 = records.stream()
            .filter(r -> r.key.equals("TCS"))
            .mapToLong(r -> r.value).max().getAsLong();
        assertEquals(3L, lastWindow1, "Window 1 TCS count should be 3");
        // The last record should be 1 (window2):
        assertEquals(1L, records.get(records.size()-1).value,
            "Window 2 TCS count should be 1");
    }
}

