import org.apache.kafka.streams.*;
import org.apache.kafka.streams.kstream.*;
import org.springframework.context.annotation.*;
import org.springframework.kafka.annotation.EnableKafkaStreams;

@Configuration @EnableKafkaStreams
public class TradeEnrichmentTopology {
    @Bean
    public KStream<String, TradeEvent> enrichedTradeStream(StreamsBuilder builder) {
        // Source 1: trade events (key=symbol):
        KStream<String, TradeEvent> trades = builder.stream("trade-executed");

        // Source 2: stock info table (key=symbol, latest value per symbol):
        KTable<String, StockInfo> stockInfo = builder.table("stock-info");

        // Join: for each trade, look up the stock's company info:
        trades
            .join(
                stockInfo,
                (tradeEvent, info) -> new EnrichedTrade(
                    tradeEvent.symbol(),
                    info != null ? info.companyName() : "Unknown",
                    info != null ? info.sector()      : "Unknown",
                    tradeEvent.qty(),
                    tradeEvent.totalValue())
            )
            .to("enriched-trades");

        return trades;
    }
}

import org.apache.kafka.streams.*;
import org.apache.kafka.streams.kstream.*;
import org.apache.kafka.common.serialization.*;
import org.apache.kafka.common.utils.Bytes;
import org.apache.kafka.streams.state.KeyValueStore;
import java.time.Duration; import java.util.*;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

// (TradeEvent record as before)

class ZerodhaAnalyticsTopology {
    StreamsBuilder build(StreamsBuilder b) {
        KStream<String,TradeEvent> trades = b.stream("trade-executed");
        KStream<String,TradeEvent> bySymbol = trades.selectKey((k,e)->e.symbol());

        // A: Large trades:
        bySymbol.filter((sym,e)->e.totalValue()>100_000).to("large-trades");

        // B: Count per symbol:
        bySymbol.groupByKey()
            .count(Materialized.<String,Long,KeyValueStore<Bytes,byte[]>>as("sym-count"))
            .toStream()
            .to("symbol-count",Produced.with(Serdes.String(),Serdes.Long()));

        // C: 5-min volume per symbol:
        bySymbol.groupByKey()
            .windowedBy(TimeWindows.ofSizeWithNoGrace(Duration.ofMinutes(5)))
            .aggregate(()->0.0,(s,e,vol)->vol+e.totalValue(),
                Materialized.as("sym-vol"))
            .toStream()
            .map((w,v)->KeyValue.pair(w.key(),v))
            .to("symbol-5min-volume",Produced.with(Serdes.String(),Serdes.Double()));
        return b;
    }
}

class ZerodhaAnalyticsTest {
    TopologyTestDriver driver;
    TestInputTopic<String,String> input;
    TestOutputTopic<String,String> largeTrades;
    TestOutputTopic<String,Long>   symbolCount;

    private String tradeJson(String sym, double total) {
        return "{\"symbol\":\""+sym+"\",\"qty\":10,\"totalValue\":"+total+",\"type\":\"BUY\"}";
    }

    @BeforeEach void setup(){
        StreamsBuilder builder = new StreamsBuilder();
        new ZerodhaAnalyticsTopology().build(builder);
        Properties props = new Properties();
        props.put(StreamsConfig.APPLICATION_ID_CONFIG,"z-test");
        props.put(StreamsConfig.BOOTSTRAP_SERVERS_CONFIG,"dummy:9092");
        props.put(StreamsConfig.DEFAULT_KEY_SERDE_CLASS_CONFIG,Serdes.String().getClass());
        props.put(StreamsConfig.DEFAULT_VALUE_SERDE_CLASS_CONFIG,Serdes.String().getClass());
        driver=new TopologyTestDriver(builder.build(),props);
        input       =driver.createInputTopic("trade-executed",new StringSerializer(),new StringSerializer());
        largeTrades =driver.createOutputTopic("large-trades",new StringDeserializer(),new StringDeserializer());
        symbolCount =driver.createOutputTopic("symbol-count",new StringDeserializer(),new LongDeserializer());
    }
    @AfterEach void teardown(){driver.close();}

    @Test void largeTrades_filtered(){
        input.pipeInput("T1",tradeJson("TCS",200_000.0));
        input.pipeInput("T2",tradeJson("INFY",50_000.0));   // small, filtered out
        input.pipeInput("T3",tradeJson("RELIANCE",150_000.0));
        assertEquals(2,largeTrades.readKeyValuesToList().size());
    }
    @Test void symbolCount_correct(){
        input.pipeInput("T1",tradeJson("TCS",10_000.0));
        input.pipeInput("T2",tradeJson("TCS",20_000.0));
        input.pipeInput("T3",tradeJson("TCS",15_000.0));
        Map<String,Long> counts=symbolCount.readKeyValuesToMap();
        assertEquals(3L,counts.get("TCS"));
    }
}
